});

import { component$ } from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  return (
    <main>
      <h1>Qwik Multi-Step Registration Wizard</h1>
      <p>
        This is a server-rendered, progressively-enhanced registration flow built
        with Qwik City, Zod, and a local SQLite database. Each step is validated
        on the server.
      </p>
      <p>
        <a href="/register/">Start the registration →</a>
      </p>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Qwik Wizard",
  meta: [
    {
      name: "description",
      content: "Multi-step registration wizard built with Qwik City",
    },
  ],
};

import { component$ } from "@builder.io/qwik";
import {
  Form,
  routeAction$,
  routeLoader$,
  zod$,
  z,
  type DocumentHead,
  type RequestHandler,
} from "@builder.io/qwik-city";
import { findUserByEmail } from "~/lib/db.server";
import { hashPassword, readSession } from "~/lib/session";

// Ensures the table exists before any read on this route fires.
export const onRequest: RequestHandler = async () => {
  const { getDb } = await import("~/lib/db.server");
  getDb();
};

export const useWizardData = routeLoader$((ev) => {
  const data = readSession(ev);
  return {
    email: data.account?.email ?? "",
  };
});

export const useAccountAction = routeAction$(
  async (values, ev) => {
    const normalisedEmail = values.email.trim().toLowerCase();

    // Uniqueness enforced against the SQLite database.
    const existing = findUserByEmail(normalisedEmail);
    if (existing) {
      return ev.fail(400, {
        fieldErrors: {
          email: "An account with this email already exists.",
        },
        values: {
          email: values.email,
        },
      });
    }

    const { hashPassword, writeSession } = await import("~/lib/session");
    writeSession(ev, {
      account: {
        email: normalisedEmail,
        passwordHash: hashPassword(values.password),
      },
    });

    throw ev.redirect(303, "/register/profile/");
  },
  zod$({
    email: z
      .string()
      .min(1, "Email is required")
      .email("Please enter a valid email address"),
    password: z
      .string()
      .min(8, "Password must be at least 8 characters")
      .regex(/[a-z]/, "Password must contain a lowercase letter")
      .regex(/[A-Z]/, "Password must contain an uppercase letter")
      .regex(/[0-9]/, "Password must contain a digit"),
    confirmPassword: z.string().min(1, "Please confirm your password"),
  }).refine((data) => data.password === data.confirmPassword, {
    message: "Passwords do not match",
    path: ["confirmPassword"],
  }),
);

export default component$(() => {
  const wizardData = useWizardData();
  const action = useAccountAction();

  const fieldErrors = action.value?.fieldErrors ?? {};
  const submitted = action.value?.values;

  const email = submitted?.email ?? wizardData.value.email ?? "";
  // Never pre-fill passwords — browsers and form autofill get it from the user.
  const password = "";
  const confirmPassword = "";

  return (
    <main>
      <div class="steps" aria-label="Wizard progress">
        <span class="active">1. Account</span>
        <span>2. Profile</span>
        <span>3. Review</span>
      </div>
      <h1>Create your account</h1>
      <p>
        Step 1 of 3. We'll save your progress on the server so you can come back
        later.
      </p>

      {Object.keys(fieldErrors).length > 0 && (
        <div class="summary-error" role="alert">
          Please fix the highlighted fields and try again.
        </div>
      )}

      <Form action={action}>
        <label>
          Email
          <input
            type="email"
            name="email"
            autoComplete="email"
            required
            value={email}
            aria-invalid={fieldErrors.email ? "true" : "false"}
          />
          {fieldErrors.email && (
            <span class="field-error">{fieldErrors.email}</span>
          )}
        </label>

        <label>
          Password
          <input
            type="password"
            name="password"
            autoComplete="new-password"
            required
            value={password}
            aria-invalid={fieldErrors.password ? "true" : "false"}
          />
          {fieldErrors.password && (
            <span class="field-error">{fieldErrors.password}</span>
          )}
        </label>

        <label>
          Confirm password
          <input
            type="password"
            name="confirmPassword"
            autoComplete="new-password"
            required
            value={confirmPassword}
            aria-invalid={fieldErrors.confirmPassword ? "true" : "false"}
          />
          {fieldErrors.confirmPassword && (
            <span class="field-error">{fieldErrors.confirmPassword}</span>
          )}
        </label>

        <div class="form-actions">
          <span />
          <button type="submit">Continue → Profile</button>
        </div>
      </Form>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Register · Account",
};

import { component$ } from "@builder.io/qwik";
import {
  Form,
  Link,
  routeAction$,
  routeLoader$,
  zod$,
  z,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { readSession, writeSession } from "~/lib/session";

export const useProfileData = routeLoader$((ev) => {
  const data = readSession(ev);
  // If they reach this step without an account, push them back.
  if (!data.account) {
    throw ev.redirect(303, "/register/");
  }
  return {
    fullName: data.profile?.fullName ?? "",
    age: data.profile?.age ?? ("" as unknown as number),
    country: data.profile?.country ?? "",
  };
});

export const useProfileAction = routeAction$(
  async (values, ev) => {
    const data = readSession(ev);
    if (!data.account) {
      throw ev.redirect(303, "/register/");
    }

    writeSession(ev, {
      profile: {
        fullName: values.fullName.trim(),
        age: values.age,
        country: values.country.trim(),
      },
    });

    throw ev.redirect(303, "/register/review/");
  },
  zod$({
    fullName: z
      .string()
      .min(2, "Full name must be at least 2 characters")
      .transform((s) => s.trim()),
    age: z.coerce
      .number({ invalid_type_error: "Age must be a number" })
      .int("Age must be a whole number")
      .min(18, "You must be at least 18 years old"),
    country: z
      .string()
      .min(1, "Country is required")
      .transform((s) => s.trim()),
  }),
);

export default component$(() => {
  const loader = useProfileData();
  const action = useProfileAction();

  const fieldErrors = action.value?.fieldErrors ?? {};
  // If validation failed the action returned the parsed input. Otherwise pre-fill
  // from the persisted session data.
  const failedInput = action.value?.failedValues;
  const fullName =
    (failedInput?.fullName as string | undefined) ?? loader.value.fullName;
  const age =
    (failedInput?.age as number | string | undefined) ?? loader.value.age;
  const country =
    (failedInput?.country as string | undefined) ?? loader.value.country;

  return (
    <main>
      <div class="steps" aria-label="Wizard progress">
        <span>
          <Link href="/register/">1. Account</Link>
        </span>
        <span class="active">2. Profile</span>
        <span>3. Review</span>
      </div>
      <h1>About you</h1>
      <p>Step 2 of 3. Tell us a little about yourself.</p>

      {Object.keys(fieldErrors).length > 0 && (
        <div class="summary-error" role="alert">
          Please fix the highlighted fields and try again.
        </div>
      )}

      <Form action={action}>
        <label>
          Full name
          <input
            type="text"
            name="fullName"
            autoComplete="name"
            required
            value={fullName}
            aria-invalid={fieldErrors.fullName ? "true" : "false"}
          />
          {fieldErrors.fullName && (
            <span class="field-error">{fieldErrors.fullName}</span>
          )}
        </label>

        <label>
          Age
          <input
            type="number"
            name="age"
            inputMode="numeric"
            min={18}
            required
            value={age as string | number}
            aria-invalid={fieldErrors.age ? "true" : "false"}
          />
          {fieldErrors.age && (
            <span class="field-error">{fieldErrors.age}</span>
          )}
        </label>

        <label>
          Country
          <input
            type="text"
            name="country"
            autoComplete="country-name"
            required
            value={country}
            aria-invalid={fieldErrors.country ? "true" : "false"}
          />
          {fieldErrors.country && (
            <span class="field-error">{fieldErrors.country}</span>
          )}
        </label>

        <div class="form-actions">
          <Link href="/register/" class="secondary">
            ← Back
          </Link>
          <button type="submit">Continue → Review</button>
        </div>
      </Form>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Register · Profile",
};

import { component$ } from "@builder.io/qwik";
import {
  Form,
  Link,
  routeAction$,
  routeLoader$,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { clearSession, readSession } from "~/lib/session";
import { createUser, findUserByEmail } from "~/lib/db.server";

export const useReviewData = routeLoader$((ev) => {
  const data = readSession(ev);
  if (!data.account) {
    throw ev.redirect(303, "/register/");
  }
  if (!data.profile) {
    throw ev.redirect(303, "/register/profile/");
  }
  return {
    email: data.account.email,
    fullName: data.profile.fullName,
    age: data.profile.age,
    country: data.profile.country,
  };
});

export const useSubmitAction = routeAction$(async (_values, ev) => {
  const data = readSession(ev);
  if (!data.account || !data.profile) {
    throw ev.redirect(303, "/register/");
  }

  // Final guard against a race where someone registered this email in another
  // tab between the account step and the submit.
  if (findUserByEmail(data.account.email)) {
    clearSession(ev);
    return ev.fail(409, {
      message: "This email was just registered in another tab.",
    });
  }

  createUser({
    email: data.account.email,
    passwordHash: data.account.passwordHash,
    fullName: data.profile.fullName,
    age: data.profile.age,
    country: data.profile.country,
  });

  // Remember the email to display on the success page, then drop the rest of
  // the session so the user cannot re-submit the form by replaying cookies.
  ev.cookie.set("registered_email", data.account.email, {
    path: "/",
    httpOnly: true,
    sameSite: "lax",
    maxAge: 60 * 10,
  });
  clearSession(ev);

  throw ev.redirect(303, "/register/success/");
});

export default component$(() => {
  const loader = useReviewData();
  const action = useSubmitAction();

  return (
    <main>
      <div class="steps" aria-label="Wizard progress">
        <span>
          <Link href="/register/">1. Account</Link>
        </span>
        <span>
          <Link href="/register/profile/">2. Profile</Link>
        </span>
        <span class="active">3. Review</span>
      </div>
      <h1>Review &amp; submit</h1>
      <p>Step 3 of 3. Please confirm your details below.</p>

      {action.value?.message && (
        <div class="summary-error" role="alert">
          {action.value.message}
        </div>
      )}

      <dl class="review-list">
        <dt>Email</dt>
        <dd>{loader.value.email}</dd>
